        SELECT lpr_seq,
        case
			when cctv_no like 'S%' then substring(cctv_no, 2, 7)
			else cctv_no
		END AS cctv_no, car_license_no, car_img_file_nm, lpr_svr_no, car_img_path_nm

        FROM t_lpr0090






                AND lpr_seq = #{lprSeq}



                AND cctv_no LIKE '%'||#{cctvNo}||'%'




                AND car_license_no = #{carLicenseNo}



                AND car_img_path_nm = #{carImgPathNm}



                AND car_img_file_nm = #{carImgFileNm}



                AND lpr_svr_no = #{lprSvrNo}





                AND lpr_seq  >=  #{startDt}



                AND lpr_seq  <=  #{endDt}






                ${sortCol} ${sortTyp}


                cctv_no ASC




            LIMIT ${limit} OFFSET ${offset}

